)
from queryweave.parser.lexer import Lexer, Token, TokenStream, TokenType


_AGGREGATES = {"COUNT", "SUM", "AVG", "MIN", "MAX"}
_COMPARISON_OPERATORS = {"=", "!=", "<>", "<", "<=", ">", ">="}
_SELECT_ALIAS_STOPPERS = {
    TokenType.FROM,
    TokenType.WHERE,
    TokenType.GROUP_BY,
    TokenType.HAVING,
    TokenType.ORDER_BY,
    TokenType.LIMIT,
    TokenType.OFFSET,
    TokenType.UNION,
    TokenType.RPAREN,
    TokenType.COMMA,
    TokenType.SEMICOLON,
    TokenType.EOF,
}
_TABLE_ALIAS_STOPPERS = {
    TokenType.JOIN,
    TokenType.LEFT,
    TokenType.RIGHT,
    TokenType.INNER,
    TokenType.FULL,
    TokenType.CROSS,
    TokenType.WHERE,
    TokenType.GROUP_BY,
    TokenType.HAVING,
